mapper.select:
SELECT id, tenant_id, email, reason, created_at
FROM SUPPRESSION_LIST
WHERE tenant_id = #{tenantId}
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT id, tenant_id, email, reason, created_at
FROM SUPPRESSION_LIST
WHERE tenant_id = #{tenantId}
  AND email = #{email}
LIMIT 1

SELECT COUNT(*)
FROM SUPPRESSION_LIST
WHERE tenant_id = #{tenantId}

mapper.delete:
DELETE FROM SUPPRESSION_LIST
WHERE tenant_id = #{tenantId}
  AND email = #{email}
